import React, { useState, useEffect } from 'react';
import CourseCard from '../components/CourseCard';
import { 
  getFeaturedCourses, 
  getStats, 
  checkHealth,
  addSampleCourses 
} from '../services/api';

const Home = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [backendStatus, setBackendStatus] = useState('checking');
  const [stats, setStats] = useState([
    { title: 'Total Notes', value: 'Loading...', icon: '📄', key: 'notes' },
    { title: 'PYQs', value: 'Loading...', icon: '📝', key: 'pyqs' },
    { title: 'Courses', value: 'Loading...', icon: '🎓', key: 'courses' },
    { title: 'Downloads', value: 'Loading...', icon: '⬇️', key: 'downloads' },
  ]);
  const [showAddCoursesBtn, setShowAddCoursesBtn] = useState(false);

  useEffect(() => {
    // Check backend connection first
    checkBackend();
    fetchData();
  }, []);

  const checkBackend = async () => {
    try {
      const health = await checkHealth();
      setBackendStatus('connected');
      console.log('✅ Backend connected:', health);
      
      // Show add courses button if no courses in DB
      if (health.course_count === 0) {
        setShowAddCoursesBtn(true);
      }
    } catch (error) {
      setBackendStatus('disconnected');
      console.error('❌ Backend connection failed:', error);
    }
  };

  const handleAddSampleCourses = async () => {
    try {
      setLoading(true);
      const result = await addSampleCourses();
      alert(`✅ ${result.message}`);
      setShowAddCoursesBtn(false);
      fetchData(); // Refresh courses
    } catch (error) {
      alert('❌ Failed to add sample courses');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async () => {
    try {
      // Fetch courses from backend
      const coursesData = await getFeaturedCourses(6);
      
      // Transform backend data to match CourseCard expectations
      const transformedCourses = coursesData.courses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branch,
        semester: course.semester,
        code: course.code,
        notes: course.notes || 0,
        pyqs: course.pyqs || 0,
        description: course.description,
        created_at: course.created_at
      }));
      
      setCourses(transformedCourses);
      
      // Fetch stats
      const statsData = await getStats();
      setStats([
        { 
          title: 'Total Notes', 
          value: `${statsData.totalNotes}+`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${statsData.totalPYQs}+`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${statsData.totalCourses}+`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${statsData.totalDownloads}+`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
    } catch (error) {
      console.error('Error fetching data:', error);
      
      // Fallback to mock data if backend fails
      setCourses([
        { 
          id: 1, 
          name: 'Data Structures', 
          branch: 'CSE', 
          semester: 3, 
          code: 'CSE201',
          notes: 25, 
          pyqs: 40,
          description: 'Introduction to data structures'
        },
        { 
          id: 2, 
          name: 'Digital Electronics', 
          branch: 'ECE', 
          semester: 2, 
          code: 'ECE202',
          notes: 18, 
          pyqs: 35,
          description: 'Digital circuits and systems'
        },
      ]);
      
      setBackendStatus('disconnected');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async () => {
    if (searchQuery.trim()) {
      alert(`Searching for: ${searchQuery}\n(Search functionality coming soon!)`);
      // TODO: Implement search API endpoint
    }
  };

  const features = [
    { title: 'Updated Content', desc: 'Regularly updated materials', icon: '✅' },
    { title: 'Easy Search', desc: 'Find materials quickly', icon: '🔍' },
    { title: 'Mobile Friendly', desc: 'Access on any device', icon: '📱' },
    { title: 'Free Forever', desc: 'All resources free', icon: '🆓' },
  ];

  const styles = {
    container: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)',
      paddingBottom: '2rem'
    },
    heroSection: {
      textAlign: 'center',
      padding: '4rem 1rem',
      background: 'linear-gradient(90deg, #4f46e5 0%, #7c3aed 100%)',
      color: 'white',
      borderRadius: '0 0 20px 20px',
      marginBottom: '2rem',
      position: 'relative'
    },
    statusBadge: {
      position: 'absolute',
      top: '10px',
      right: '10px',
      padding: '5px 15px',
      borderRadius: '20px',
      fontSize: '0.9rem',
      fontWeight: 'bold',
      background: backendStatus === 'connected' ? '#10b981' : '#ef4444',
      display: 'flex',
      alignItems: 'center',
      gap: '5px'
    },
    heroTitle: {
      fontSize: '2.5rem',
      fontWeight: 'bold',
      marginBottom: '1rem',
    },
    heroSubtitle: {
      fontSize: '1.1rem',
      opacity: 0.9,
      marginBottom: '2rem',
      maxWidth: '600px',
      margin: '0 auto 2rem'
    },
    searchContainer: {
      maxWidth: '600px',
      margin: '0 auto',
      display: 'flex',
      gap: '10px'
    },
    searchInput: {
      flex: 1,
      padding: '1rem 1.5rem',
      borderRadius: '25px',
      border: 'none',
      fontSize: '1rem',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      outline: 'none'
    },
    searchButton: {
      padding: '0 2rem',
      borderRadius: '25px',
      border: 'none',
      background: '#10b981',
      color: 'white',
      fontWeight: 'bold',
      fontSize: '1rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#059669',
        transform: 'scale(1.05)'
      }
    },
    addCoursesBtn: {
      marginTop: '1rem',
      padding: '0.75rem 1.5rem',
      background: '#f59e0b',
      color: 'white',
      border: 'none',
      borderRadius: '25px',
      fontWeight: 'bold',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#d97706'
      }
    },
    statsSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem'
    },
    statsGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '1rem',
    },
    statCard: {
      background: 'white',
      padding: '1.5rem',
      borderRadius: '10px',
      textAlign: 'center',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      transition: 'transform 0.3s, box-shadow 0.3s',
      '&:hover': {
        transform: 'translateY(-5px)',
        boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
      }
    },
    statIcon: {
      fontSize: '2.5rem',
      marginBottom: '0.5rem'
    },
    statNumber: {
      fontSize: '2rem',
      fontWeight: 'bold',
      color: '#4f46e5',
      marginBottom: '0.25rem'
    },
    statLabel: {
      color: '#6b7280',
      fontSize: '0.9rem'
    },
    coursesSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem'
    },
    sectionTitle: {
      fontSize: '2rem',
      textAlign: 'center',
      marginBottom: '2rem',
      color: '#1f2937'
    },
    coursesGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(1, 1fr)',
      gap: '1.5rem',
    },
    viewAll: {
      textAlign: 'center',
      marginTop: '2rem'
    },
    viewAllBtn: {
      padding: '0.75rem 2rem',
      background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
      color: 'white',
      border: 'none',
      borderRadius: '25px',
      fontWeight: 'bold',
      fontSize: '1rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        transform: 'scale(1.05)',
        boxShadow: '0 5px 15px rgba(79, 70, 229, 0.4)'
      }
    },
    featuresSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem'
    },
    featuresGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(1, 1fr)',
      gap: '1.5rem',
    },
    featureCard: {
      background: 'white',
      padding: '1.5rem',
      borderRadius: '10px',
      textAlign: 'center',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      transition: 'transform 0.3s',
      '&:hover': {
        transform: 'translateY(-3px)'
      }
    },
    featureIcon: {
      fontSize: '2.5rem',
      marginBottom: '1rem'
    },
    loading: {
      textAlign: 'center',
      padding: '3rem',
      color: '#6b7280',
      fontSize: '1.1rem'
    },
    error: {
      textAlign: 'center',
      padding: '2rem',
      color: '#ef4444',
      background: '#fee2e2',
      borderRadius: '10px',
      margin: '2rem'
    },
    connectionInfo: {
      textAlign: 'center',
      marginTop: '1rem',
      fontSize: '0.9rem',
      color: 'rgba(255,255,255,0.8)'
    }
  };

  // Responsive styles
  const updateResponsiveStyles = () => {
    const width = window.innerWidth;
    
    if (width >= 768) {
      styles.statsGrid.gridTemplateColumns = 'repeat(4, 1fr)';
      styles.coursesGrid.gridTemplateColumns = 'repeat(2, 1fr)';
      styles.featuresGrid.gridTemplateColumns = 'repeat(2, 1fr)';
    } else {
      styles.statsGrid.gridTemplateColumns = 'repeat(2, 1fr)';
      styles.coursesGrid.gridTemplateColumns = 'repeat(1, 1fr)';
      styles.featuresGrid.gridTemplateColumns = 'repeat(1, 1fr)';
    }
    
    if (width >= 1024) {
      styles.coursesGrid.gridTemplateColumns = 'repeat(3, 1fr)';
      styles.featuresGrid.gridTemplateColumns = 'repeat(4, 1fr)';
    }
  };

  // Update responsive styles on mount and resize
  useEffect(() => {
    updateResponsiveStyles();
    window.addEventListener('resize', updateResponsiveStyles);
    return () => window.removeEventListener('resize', updateResponsiveStyles);
  }, []);

  return (
    <div style={styles.container}>
      {/* Hero Section */}
      <section style={styles.heroSection}>
        <div style={styles.statusBadge}>
          {backendStatus === 'connected' ? '✅ Connected' : '❌ Disconnected'}
          <span style={{ fontSize: '0.8rem', marginLeft: '5px' }}>
            {backendStatus === 'connected' ? 'http://localhost:5000' : 'Offline'}
          </span>
        </div>
        
        <h1 style={styles.heroTitle}>Welcome to College Notes Hub</h1>
        <p style={styles.heroSubtitle}>
          Your one-stop destination for notes, PYQs, syllabus and study materials
        </p>
        
        <div style={styles.searchContainer}>
          <input
            type="text"
            placeholder="Search courses, notes, PYQs..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
            style={styles.searchInput}
          />
          <button 
            onClick={handleSearch}
            style={styles.searchButton}
          >
            🔍 Search
          </button>
        </div>

        {showAddCoursesBtn && backendStatus === 'connected' && (
          <button 
            onClick={handleAddSampleCourses}
            style={styles.addCoursesBtn}
            disabled={loading}
          >
            {loading ? 'Adding...' : '➕ Add Sample Courses to Database'}
          </button>
        )}

        <div style={styles.connectionInfo}>
          Backend: http://localhost:5000 | Database: {courses.length > 0 ? 'Loaded' : 'Empty'}
        </div>
      </section>

      {/* Stats Section */}
      <section style={styles.statsSection}>
        <div style={styles.statsGrid}>
          {stats.map((stat, index) => (
            <div key={index} style={styles.statCard}>
              <div style={styles.statIcon}>{stat.icon}</div>
              <h3 style={styles.statNumber}>{stat.value}</h3>
              <p style={styles.statLabel}>{stat.title}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Featured Courses */}
      <section style={styles.coursesSection}>
        <h2 style={styles.sectionTitle}>Featured Courses</h2>
        
        {loading ? (
          <div style={styles.loading}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>⏳</div>
            <p>Loading courses from backend...</p>
            <p>Connecting to: http://localhost:5000</p>
            <p>Backend Status: <strong>{backendStatus}</strong></p>
          </div>
        ) : courses.length === 0 && backendStatus === 'connected' ? (
          <div style={styles.error}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>📭</div>
            <h3>No courses found in database!</h3>
            <p>Click the "Add Sample Courses" button above to populate the database.</p>
            <button 
              onClick={handleAddSampleCourses}
              style={{...styles.viewAllBtn, background: '#f59e0b', marginTop: '1rem'}}
              disabled={loading}
            >
              {loading ? 'Adding...' : '➕ Add Sample Courses'}
            </button>
          </div>
        ) : courses.length === 0 && backendStatus === 'disconnected' ? (
          <div style={styles.error}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>🔌</div>
            <h3>Backend Connection Failed!</h3>
            <p>Make sure backend is running at: http://localhost:5000</p>
            <p>Run in terminal: <code>cd backend && python app.py</code></p>
            <button 
              onClick={fetchData}
              style={{...styles.viewAllBtn, background: '#ef4444', marginTop: '1rem'}}
            >
              🔄 Retry Connection
            </button>
          </div>
        ) : (
          <>
            <div style={styles.coursesGrid}>
              {courses.map(course => (
                <CourseCard key={course.id} course={course} />
              ))}
            </div>
            
            <div style={styles.viewAll}>
              <button 
                style={styles.viewAllBtn}
                onClick={() => window.location.href = '/courses'}
              >
                📚 View All Courses →
              </button>
            </div>
          </>
        )}
      </section>

      {/* Features Section */}
      <section style={styles.featuresSection}>
        <h2 style={styles.sectionTitle}>Why Choose Notes Hub?</h2>
        <div style={styles.featuresGrid}>
          {features.map((feature, index) => (
            <div key={index} style={styles.featureCard}>
              <div style={styles.featureIcon}>{feature.icon}</div>
              <h3 style={{ marginBottom: '0.5rem', color: '#1f2937' }}>{feature.title}</h3>
              <p style={{ color: '#6b7280', lineHeight: '1.5' }}>{feature.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Backend Info */}
      <div style={{
        textAlign: 'center',
        marginTop: '3rem',
        padding: '1rem',
        color: '#6b7280',
        fontSize: '0.9rem'
      }}>
        <p>
          <strong>Backend Status:</strong> {backendStatus} | 
          <strong> Courses Loaded:</strong> {courses.length} | 
          <strong> API:</strong> http://localhost:5000
        </p>
        <p style={{ fontSize: '0.8rem', marginTop: '0.5rem' }}>
          {backendStatus === 'connected' ? '✅ Frontend-Backend Connection Successful!' : '❌ Check backend server'}
        </p>
      </div>
    </div>
  );
};

export default Home;
